#include "controller.h"
#include <string.h>

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
    controller->clear_streak_count = 0;
}

static bool sensors_valid(const controller_t *controller, uint32_t now_ms)
{
    return (now_ms - controller->last_turbidity_ms <= CONTROLLER_SENSOR_TIMEOUT_MS) &&
           (now_ms - controller->last_level_ms <= CONTROLLER_SENSOR_TIMEOUT_MS);
}

static bool level_sufficient(const controller_t *controller)
{
    return controller->has_valid_level && 
           controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL;
}

static bool level_complete(const controller_t *controller)
{
    return controller->has_valid_level && 
           controller->last_level < CONTROLLER_COMPLETE_LEVEL;
}

static void controller_set_filtering(controller_t *controller, uint32_t now_ms)
{
    controller->filter_on = true;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_FILTERING;
    controller->clear_streak_count = 0;
}

static void controller_set_filter_off(controller_t *controller, uint32_t now_ms)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SETTLING;
    controller->settling_started_ms = now_ms;
}

static void controller_set_draining(controller_t *controller, uint32_t now_ms)
{
    controller->filter_on = false;
    controller->drain_open = true;
    controller->state = CONTROLLER_STATE_DRAINING;
}

static void controller_set_complete(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_COMPLETE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    uint32_t now_ms = input.now_ms;

    /* Track sensor freshness for timeout detection */
    bool turbidity_valid_now = false;
    bool level_valid_now = false;
    bool sensor_timeout = false;

    /* Update controller state based on input kind */
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = now_ms;
        turbidity_valid_now = true;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = now_ms;
        level_valid_now = true;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        sensor_timeout = true;
        break;
    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        sensor_timeout = true;
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        /* No input - check for timeout based on elapsed time */
        break;
    }

    /* Check for sensor timeout condition (both sensors stale) */
    if (!sensor_timeout && now_ms > 0) {
        bool turbidity_stale = controller->has_valid_turbidity && 
                               (now_ms - controller->last_turbidity_ms > CONTROLLER_SENSOR_TIMEOUT_MS);
        bool level_stale = controller->has_valid_level && 
                           (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS);
        if (turbidity_stale || level_stale) {
            sensor_timeout = true;
        }
    }

    /* Handle timeout - go to safe idle */
    if (sensor_timeout) {
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;

        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
        output.timed_out = true;
        return output;
    }

    /* Save previous state for change detection */
    controller_state_t prev_state = controller->state;
    bool prev_filter_on = controller->filter_on;
    bool prev_drain_open = controller->drain_open;

    /* State machine logic */
    switch (controller->state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        /* Stay in safe idle until both sensors are valid and level >= 40 */
        if (controller->has_valid_turbidity && controller->has_valid_level) {
            if (level_sufficient(controller)) {
                /* Check turbidity - cloudy starts filtering */
                if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller_set_filtering(controller, now_ms);
                } else {
                    /* Clear but level sufficient - start filtering to be safe */
                    controller_set_filtering(controller, now_ms);
                }
            } else if (level_complete(controller)) {
                controller_set_complete(controller);
            }
        }
        break;

    case CONTROLLER_STATE_FILTERING:
        /* Update clear streak based on turbidity readings */
        if (turbidity_valid_now) {
            if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                controller->clear_streak_count++;
            } else {
                controller->clear_streak_count = 0;
            }

            /* Check for settling condition: clear streak of 3 and level >= 40 */
            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED && 
                level_sufficient(controller)) {
                controller_set_filter_off(controller, now_ms);
            }
        } else if (level_complete(controller)) {
            /* Level dropped below drain threshold - go complete */
            controller_set_complete(controller);
        }
        break;

    case CONTROLLER_STATE_SETTLING:
        /* Check for disturbance: TURB > 40 returns to filtering */
        if (turbidity_valid_now && controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            controller_set_filtering(controller, now_ms);
        } else if (!level_sufficient(controller)) {
            /* Level dropped below threshold - go complete */
            controller_set_complete(controller);
        } else {
            /* Check if settling time has elapsed (400ms) and latest turbidity is clear */
            uint32_t settling_elapsed = now_ms - controller->settling_started_ms;
            if (settling_elapsed >= CONTROLLER_SETTLING_MS && 
                controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                controller_set_draining(controller, now_ms);
            }
        }
        break;

    case CONTROLLER_STATE_DRAINING:
        /* Check for disturbance: TURB > 50 and level >= 40 returns to filtering */
        if (turbidity_valid_now && 
            controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
            level_sufficient(controller)) {
            controller_set_filtering(controller, now_ms);
        } else if (!level_sufficient(controller)) {
            /* Level dropped below threshold - go complete */
            controller_set_complete(controller);
        }
        break;

    case CONTROLLER_STATE_COMPLETE:
        /* Stay in complete until sensors become stale */
        if (level_sufficient(controller)) {
            /* Level increased again - might need to re-filter */
            if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                controller_set_filtering(controller, now_ms);
            }
        } else if (level_complete(controller)) {
            /* Still below drain threshold */
        }
        break;

    default:
        controller_set_safe_idle(controller);
        break;
    }

    /* Output the current controller state */
    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (prev_filter_on != controller->filter_on) ||
                     (prev_drain_open != controller->drain_open) ||
                     (prev_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

